import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import toast from "react-hot-toast";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      await login(email, password);
      toast.success("Welcome back!");
      navigate("/dashboard");
    } catch (err) {
      toast.error(err.response?.data?.message || "Login failed");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    width: "100%",
    padding: "14px 18px",
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.15)",
    borderRadius: "14px",
    color: "#fff",
    fontSize: "15px",
    outline: "none",
    boxSizing: "border-box",
    backdropFilter: "blur(10px)",
    transition: "all 0.3s ease",
  };

  const labelStyle = {
    display: "block",
    fontSize: "12px",
    color: "#e5e7eb",
    marginBottom: "8px",
    fontWeight: "600",
    letterSpacing: "1px",
  };

  return (
    <>
      <style>
        {`
          @keyframes gradientBG {
            0% {
              background-position: 0% 50%;
            }
            50% {
              background-position: 100% 50%;
            }
            100% {
              background-position: 0% 50%;
            }
          }

          @keyframes float {
            0% {
              transform: translateY(0px);
            }
            50% {
              transform: translateY(-10px);
            }
            100% {
              transform: translateY(0px);
            }
          }

          .login-card:hover {
            transform: translateY(-5px);
            box-shadow:
              0 20px 40px rgba(0,0,0,0.3),
              0 0 50px rgba(139,92,246,0.4);
          }

          .login-input:focus {
            border-color: #8b5cf6;
            box-shadow: 0 0 20px rgba(139,92,246,0.4);
          }

          .login-btn:hover {
            transform: translateY(-2px);
            box-shadow:
              0 15px 35px rgba(124,58,237,0.6);
          }
        `}
      </style>

      <div
        style={{
          minHeight: "100vh",
          background:
            "linear-gradient(-45deg, #667eea, #764ba2, #6a11cb, #2575fc, #ff6ec4)",
          backgroundSize: "400% 400%",
          animation: "gradientBG 15s ease infinite",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          padding: "20px",
          position: "relative",
          overflow: "hidden",
          fontFamily: "'Poppins', sans-serif",
        }}
      >
        {/* Background Glow Effects */}
        <div
          style={{
            position: "absolute",
            width: "350px",
            height: "350px",
            borderRadius: "50%",
            background: "#8b5cf6",
            filter: "blur(120px)",
            top: "-100px",
            left: "-100px",
            opacity: 0.4,
          }}
        />

        <div
          style={{
            position: "absolute",
            width: "350px",
            height: "350px",
            borderRadius: "50%",
            background: "#06b6d4",
            filter: "blur(120px)",
            bottom: "-100px",
            right: "-100px",
            opacity: 0.4,
          }}
        />

        <div
          className="login-card"
          style={{
            width: "100%",
            maxWidth: "450px",
            padding: "50px 40px",
            borderRadius: "28px",
            background: "rgba(255,255,255,0.08)",
            backdropFilter: "blur(25px)",
            WebkitBackdropFilter: "blur(25px)",
            border: "1px solid rgba(255,255,255,0.15)",
            boxShadow:
              "0 8px 32px rgba(0,0,0,0.25), 0 0 40px rgba(139,92,246,0.25)",
            transition: "all 0.4s ease",
            zIndex: 1,
          }}
        >
          {/* Logo Section */}
          <div style={{ textAlign: "center", marginBottom: "40px" }}>
            <div
              style={{
                fontSize: "75px",
                marginBottom: "15px",
                animation: "float 3s ease-in-out infinite",
                filter: "drop-shadow(0 0 25px rgba(255,255,255,0.5))",
              }}
            >
              🎓
            </div>

            <h1
              style={{
                margin: 0,
                fontSize: "36px",
                fontWeight: "800",
                background:
                  "linear-gradient(90deg,#60a5fa,#c084fc,#f472b6,#f59e0b)",
                WebkitBackgroundClip: "text",
                WebkitTextFillColor: "transparent",
              }}
            >
              EduAdmin
            </h1>

            <p
              style={{
                color: "#e2e8f0",
                marginTop: "10px",
                fontSize: "15px",
              }}
            >
              Student Automation System
            </p>
          </div>

          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom: "22px" }}>
              <label style={labelStyle}>EMAIL ADDRESS</label>
              <input
                className="login-input"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="admin@school.com"
                style={inputStyle}
                required
              />
            </div>

            <div style={{ marginBottom: "30px" }}>
              <label style={labelStyle}>PASSWORD</label>
              <input
                className="login-input"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                style={inputStyle}
                required
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="login-btn"
              style={{
                width: "100%",
                padding: "15px",
                border: "none",
                borderRadius: "14px",
                fontSize: "16px",
                fontWeight: "700",
                cursor: loading ? "not-allowed" : "pointer",
                background:
                  "linear-gradient(135deg,#4f46e5,#7c3aed,#ec4899)",
                color: "#fff",
                boxShadow: "0 10px 25px rgba(124,58,237,0.5)",
                transition: "all 0.3s ease",
              }}
            >
              {loading ? "⏳ Signing in..." : "🚀 Sign In"}
            </button>
          </form>

          <div
            style={{
              marginTop: "25px",
              textAlign: "center",
              color: "#cbd5e1",
              fontSize: "13px",
            }}
          >
            Secure Login • Student Management Portal
          </div>
        </div>
      </div>
    </>
  );
}
